using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithData();
            _controller = new StudentsController(_context);
            SetupController(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SetupController(Controller controller)
        {
            controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            controller.TempData = new TempDataDictionary(
                controller.ControllerContext.HttpContext,
                new SessionStateTempDataProvider(new SessionStateSessionStore()));
        }

        [Fact]
        public void Index_NoParameters_ReturnsViewWithStudents()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.True(model.Count > 0);
        }

        [Fact]
        public void Index_SortByNameDesc_ReturnsSortedStudents()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            // Should be descending by last name
            var names = model.Select(s => s.LastName).ToList();
            var sortedNames = names.OrderByDescending(n => n).ToList();
            Assert.Equal(sortedNames, names);
        }

        [Fact]
        public void Index_SortByDate_ReturnsSortedByDate()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            var dates = model.Select(s => s.EnrollmentDate).ToList();
            var sortedDates = dates.OrderBy(d => d).ToList();
            Assert.Equal(sortedDates, dates);
        }

        [Fact]
        public void Index_SortByDateDesc_ReturnsSortedByDateDesc()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            var dates = model.Select(s => s.EnrollmentDate).ToList();
            var sortedDates = dates.OrderByDescending(d => d).ToList();
            Assert.Equal(sortedDates, dates);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Carson", model.First().FirstMidName);
        }

        [Fact]
        public void Index_SearchStringNull_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, 1) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAsc()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            var names = model.Select(s => s.LastName).ToList();
            var sortedNames = names.OrderBy(n => n).ToList();
            Assert.Equal(sortedNames, names);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as Student;
            Assert.NotNull(model);
            Assert.Equal(1, model.ID);
            Assert.Equal("Carson", model.FirstMidName);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as Student;
            Assert.NotNull(model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);

            // Verify student was added
            var saved = _context.Students.FirstOrDefault(s => s.LastName == "Student");
            Assert.NotNull(saved);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(student, result.Model);
        }

        [Fact]
        public void Create_Post_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_DateBelow1753_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as Student;
            Assert.NotNull(model);
            Assert.Equal(1, model.ID);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = _context.Students.AsNoTracking().First(s => s.ID == 1);
            student.FirstMidName = "Updated";

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student { ID = 1, EnrollmentDate = DateTime.Parse("2023-01-01") };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as Student;
            Assert.NotNull(model);
            Assert.Equal(1, model.ID);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
        {
            var countBefore = _context.Students.Count();

            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(countBefore - 1, _context.Students.Count());
        }
    }

    /// <summary>
    /// Simple session store for TempData in tests.
    /// </summary>
    internal class SessionStateTempDataProvider : ITempDataProvider
    {
        private readonly SessionStateSessionStore _store;

        public SessionStateTempDataProvider(SessionStateSessionStore store)
        {
            _store = store;
        }

        public IDictionary<string, object?> LoadTempData(HttpContext context)
        {
            return _store.Data;
        }

        public void SaveTempData(HttpContext context, IDictionary<string, object?> values)
        {
            _store.Data = values as Dictionary<string, object?> ?? new Dictionary<string, object?>(values!);
        }
    }

    internal class SessionStateSessionStore
    {
        public Dictionary<string, object?> Data { get; set; } = new();
    }
}

