        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 100);

            var result = _controller.Create(course, fileMock.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);

            var saved = _context.Courses.Find(8888);
            Assert.NotNull(saved);
            Assert.NotNull(saved.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_WithInvalidExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 7777,
                Title = "Bad Image",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.exe", "application/octet-stream", 100);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_FileTooLarge_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 7776,
                Title = "Large File",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit(1050) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as Course;
            Assert.NotNull(model);
            Assert.Equal("Chemistry", model.Title);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(99999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            course.Title = "Updated Chemistry";

            var result = _controller.Edit(course, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, Credits = 3, DepartmentID = 1 };

            var result = _controller.Edit(course, null!) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Post_WithInvalidExtension_ReturnsViewWithError()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            var fileMock = CreateMockFormFile("test.txt", "text/plain", 100);

            var result = _controller.Edit(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as Course;
            Assert.NotNull(model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
        {
            var countBefore = _context.Courses.Count();

            var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(countBefore - 1, _context.Courses.Count());
        }

        private static Mock<IFormFile> CreateMockFormFile(string fileName, string contentType, long length)
        {
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.ContentType).Returns(contentType);
            fileMock.Setup(f => f.Length).Returns(length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => { });
            return fileMock;
        }
    }
}

