{"file_text": "using ContosoUniversity.Models;
using System;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class ModelTests
    {
        [Fact]
        public void Person_FullName_ReturnsCombinedName()
        {
            var student = new Student
            {
                FirstMidName = "Carson",
                LastName = "Alexander"
            };

            Assert.Equal("Alexander, Carson", student.FullName);
        }

        [Fact]
        public void Person_FullName_WithInstructor_ReturnsCombinedName()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie"
            };

            Assert.Equal("Abercrombie, Kim", instructor.FullName);
        }

        [Fact]
        public void Student_HasEnrollmentDate()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            Assert.Equal(new DateTime(2023, 9, 1), student.EnrollmentDate);
        }

        [Fact]
        public void Instructor_HasHireDate()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-15")
            };

            Assert.Equal(new DateTime(2020, 1, 15), instructor.HireDate);
        }

        [Fact]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/chem.jpg"
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/images/chem.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Department_Properties_SetCorrectly()
        {
            var department = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 1
            };

            Assert.Equal(1, department.DepartmentID);
            Assert.Equal("Engineering", department.Name);
            Assert.Equal(350000, department.Budget);
            Assert.Equal(1, department.InstructorID);
        }

        [Fact]
        public void Department_NullableInstructorID()
        {
            var department = new Department
            {
                Name = "No Admin",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01"),
                InstructorID = null
            };

            Assert.Null(department.InstructorID);
        }

        [Fact]
        public void Enrollment_Properties_SetCorrectly()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = Grade.A
            };

            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(1050, enrollment.CourseID);
            Assert.Equal(1, enrollment.StudentID);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_NullableGrade()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = null
            };

            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            var assignment = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1050
            };

            Assert.Equal(1, assignment.InstructorID);
            Assert.Equal(1050, assignment.CourseID);
        }

        [Fact]
        public void OfficeAssignment_Properties_SetCorrectly()
        {
            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Smith 17"
            };

            Assert.Equal(1, office.InstructorID);
            Assert.Equal("Smith 17", office.Location);
        }

        [Fact]
        public void Notification_Properties_SetCorrectly()
        {
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New Student created",
                CreatedAt = DateTime.Parse("2023-06-15"),
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("New Student created", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void Notification_MarkRead_SetsProperties()
        {
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Course",
                EntityId = "1",
                Operation = "UPDATE",
                Message = "Course updated",
                CreatedAt = DateTime.Now,
                IsRead = false
            };

            notification.IsRead = true;
            notification.ReadAt = DateTime.Now;

            Assert.True(notification.IsRead);
            Assert.NotNull(notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        [Fact]
        public void Grade_HasExpectedValues()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }
    }
