using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithData();
            _controller = new InstructorsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_NoParameters_ReturnsViewWithInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model);
            Assert.True(model.Instructors.Any());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var result = _controller.Index(1, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model);
            Assert.NotNull(model.Courses);
            Assert.True(model.Courses.Any());
        }

        [Fact]
        public void Index_WithInstructorIdAndCourseId_PopulatesEnrollments()
        {
            var result = _controller.Index(1, 1050) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as Instructor;
            Assert.NotNull(model);
            Assert.Equal("Kim", model.FirstMidName);
            Assert.Equal("Abercrombie", model.LastName);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithAssignedCourses()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as Instructor;
            Assert.NotNull(model);
            Assert.NotNull(model.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-15"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);

            var saved = _context.Instructors.FirstOrDefault(i => i.LastName == "Instructor");
            Assert.NotNull(saved);
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Course",
                LastName = "Assigned",
                HireDate = DateTime.Parse("2020-01-15"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var selectedCourses = new[] { "1050", "4022" };
            var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);

            var saved = _context.Instructors
                .Include(i => i.CourseAssignments)
                .FirstOrDefault(i => i.LastName == "Assigned");
            Assert.NotNull(saved);
            Assert.Equal(2, saved.CourseAssignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-15"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null!) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as Instructor;
            Assert.NotNull(model);
            Assert.Equal(1, model.ID);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as Instructor;
            Assert.NotNull(model);
            Assert.Equal(1, model.ID);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
        {
            // Use instructor2 (ID=2) who has no office assignment
            var countBefore = _context.Instructors.Count();

            var result = _controller.DeleteConfirmed(2) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(countBefore - 1, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_InstructorWithDepartment_NullsDepartmentAdministrator()
        {
            // Assign instructor as department admin
            var dept = _context.Departments.First(d => d.DepartmentID == 1);
            dept.InstructorID = 1;
            _context.SaveChanges();

            _controller.DeleteConfirmed(1);

            var updatedDept = _context.Departments.First(d => d.DepartmentID == 1);
            Assert.Null(updatedDept.InstructorID);
        }
    }
}

