using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithData();
            _controller = new NotificationsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            // Drain the queue first
            Services.NotificationService tempService = new();
            while (tempService.ReceiveNotification() != null) { }
            tempService.Dispose();

            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var json = result.Value;
            Assert.NotNull(json);

            // Access via dynamic or reflection
            var type = json.GetType();
            var successProp = type.GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp.GetValue(json)!);

            var countProp = type.GetProperty("count");
            Assert.NotNull(countProp);
            Assert.Equal(0, (int)countProp.GetValue(json)!);
        }

        [Fact]
        public void GetNotifications_WithMessages_ReturnsNotifications()
        {
            // Drain existing
            Services.NotificationService tempService = new();
            while (tempService.ReceiveNotification() != null) { }

            // Send some notifications
            tempService.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
            tempService.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE);
            tempService.Dispose();

            var result = _controller.GetNotifications();
            var json = result.Value;
            Assert.NotNull(json);

            var type = json.GetType();
            var successProp = type.GetProperty("success");
            Assert.True((bool)successProp!.GetValue(json)!);

            var countProp = type.GetProperty("count");
            Assert.True((int)countProp!.GetValue(json)! >= 1);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.NotNull(result);
            var json = result.Value;
            Assert.NotNull(json);

            var type = json.GetType();
            var successProp = type.GetProperty("success");
            Assert.True((bool)successProp!.GetValue(json)!);
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
        }
    }
}

