using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbContextFactory.Create();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void Context_CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First(s => s.LastName == "User");
            Assert.Equal("Test", retrieved.FirstMidName);
        }

        [Fact]
        public void Context_CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.First(i => i.LastName == "Instructor");
            Assert.Equal("Test", retrieved.FirstMidName);
        }

        [Fact]
        public void Context_CanAddAndRetrieveDepartment()
        {
            var department = new Department
            {
                Name = "Science",
                Budget = 250000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            _context.Departments.Add(department);
            _context.SaveChanges();

            var retrieved = _context.Departments.First(d => d.Name == "Science");
            Assert.Equal(250000, retrieved.Budget);
        }

        [Fact]
        public void Context_CanAddAndRetrieveCourse()
        {
            var department = new Department
            {
                Name = "TestDept",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01")
            };
            _context.Departments.Add(department);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 5555,
                Title = "TestCourse",
                Credits = 3,
                DepartmentID = department.DepartmentID
            };

            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.First(c => c.CourseID == 5555);
            Assert.Equal("TestCourse", retrieved.Title);
        }

        [Fact]
        public void Context_CourseAssignment_CompositeKey()
        {
            var instructor = new Instructor
            {
                FirstMidName = "A",
                LastName = "B",
                HireDate = DateTime.Parse("2020-01-01")
            };
            _context.Instructors.Add(instructor);

            var department = new Department
            {
                Name = "Dept",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01")
            };
            _context.Departments.Add(department);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 6666,
                Title = "Course",
                Credits = 3,
                DepartmentID = department.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var assignment = new CourseAssignment
            {
                CourseID = course.CourseID,
                InstructorID = instructor.ID
            };
            _context.CourseAssignments.Add(assignment);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments
                .First(ca => ca.CourseID == course.CourseID && ca.InstructorID == instructor.ID);
            Assert.NotNull(retrieved);
        }

        [Fact]
        public void Context_Enrollment_Relationship()
        {
            var student = new Student
            {
                FirstMidName = "E",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };
            _context.Students.Add(student);

            var department = new Department
            {
                Name = "Dept2",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01")
            };
            _context.Departments.Add(department);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 7777,
                Title = "EnrollCourse",
                Credits = 3,
                DepartmentID = department.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment
            {
                StudentID = student.ID,
                CourseID = course.CourseID,
                Grade = Grade.A
            };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments
                .Include(e => e.Student)
                .Include(e => e.Course)
                .First(e => e.StudentID == student.ID && e.CourseID == course.CourseID);

            Assert.Equal(Grade.A, retrieved.Grade);
            Assert.Equal("Student", retrieved.Student.LastName);
            Assert.Equal("EnrollCourse", retrieved.Course.Title);
        }

        [Fact]
        public void Context_OfficeAssignment_OneToOne()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Office",
                LastName = "Test",
                HireDate = DateTime.Parse("2020-01-01")
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var office = new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Room 101"
            };
            _context.OfficeAssignments.Add(office);
            _context.SaveChanges();

            var retrieved = _context.OfficeAssignments
                .Include(o => o.Instructor)
                .First(o => o.InstructorID == instructor.ID);

            Assert.Equal("Room 101", retrieved.Location);
            Assert.Equal("Test", retrieved.Instructor.LastName);
        }

        [Fact]
        public void Context_DbSets_AreNotNull()
        {
            Assert.NotNull(_context.Courses);
            Assert.NotNull(_context.Enrollments);
            Assert.NotNull(_context.Departments);
            Assert.NotNull(_context.OfficeAssignments);
            Assert.NotNull(_context.CourseAssignments);
            Assert.NotNull(_context.People);
            Assert.NotNull(_context.Students);
            Assert.NotNull(_context.Instructors);
            Assert.NotNull(_context.Notifications);
        }
    }
}

