public static void SeedData(SchoolContext context)
{
    var department = new Department
    {
        DepartmentID = 1,
        Name = "Engineering",
        Budget = 350000,
        StartDate = DateTime.Parse("2007-09-01")
    };
    context.Departments.Add(department);

    var department2 = new Department
    {
        DepartmentID = 2,
        Name = "Mathematics",
        Budget = 100000,
        StartDate = DateTime.Parse("2007-09-01")
    };
    context.Departments.Add(department2);
    context.SaveChanges();

    var instructor = new Instructor
    {
        FirstMidName = "Kim",
        LastName = "Abercrombie",
        HireDate = DateTime.Parse("1995-03-11"),
        CourseAssignments = new List<CourseAssignment>(),
        OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
    };
    context.Instructors.Add(instructor);

    var instructor2 = new Instructor
    {
        FirstMidName = "Fadi",
        LastName = "Fakhouri",
        HireDate = DateTime.Parse("2002-07-06"),
        CourseAssignments = new List<CourseAssignment>()
    };
    context.Instructors.Add(instructor2);

    context.SaveChanges();

    var course1 = new Course
    {
        CourseID = 1050,
        Title = "Chemistry",
        Credits = 3,
        DepartmentID = 1
    };
    context.Courses.Add(course1);

    var course2 = new Course
    {
        CourseID = 4022,
        Title = "Microeconomics",
        Credits = 3,
        DepartmentID = 2
    };
    context.Courses.Add(course2);

    context.SaveChanges();

    // Add course assignments
    context.CourseAssignments.Add(new CourseAssignment { CourseID = 1050, InstructorID = instructor.ID });
    context.SaveChanges();

    var student1 = new Student
    {
        FirstMidName = "Carson",
        LastName = "Alexander",
        EnrollmentDate = DateTime.Parse("2010-09-01")
    };
    context.Students.Add(student1);

    var student2 = new Student
    {
        FirstMidName = "Meredith",
        LastName = "Alonso",
        EnrollmentDate = DateTime.Parse("2012-09-01")
    };
    context.Students.Add(student2);

    var student3 = new Student
    {
        FirstMidName = "Arturo",
        LastName = "Anand",
        EnrollmentDate = DateTime.Parse("2013-09-01")
    };
    context.Students.Add(student3);

    context.SaveChanges();

    context.Enrollments.Add(new Enrollment
    {
        StudentID = student1.ID,
        CourseID = 1050,
        Grade = Grade.A
    });

    context.Enrollments.Add(new Enrollment
    {
        StudentID = student2.ID,
        CourseID = 4022,
        Grade = Grade.B
    });

    context.SaveChanges();
}

