using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;
        private readonly int _studentId1;
        private readonly int _studentId2;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithData();
            _controller = new StudentsController(_context);
            SetupController(_controller);
            _studentId1 = _context.Students.First(s => s.LastName == "Alexander").ID;
            _studentId2 = _context.Students.First(s => s.LastName == "Alonso").ID;
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SetupController(Controller controller)
        {
            controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            controller.TempData = new TempDataDictionary(
                controller.ControllerContext.HttpContext,
                new SessionStateTempDataProvider(new SessionStateSessionStore()));
        }

        [Fact]
        public void Index_NoParameters_ReturnsViewWithStudents()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.True(model.Count > 0);
        }

        [Fact]
        public void Index_SortByNameDesc_ReturnsSortedStudents()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            var names = model.Select(s => s.LastName).ToList();
            var sortedNames = names.OrderByDescending(n => n).ToList();
            Assert.Equal(sortedNames, names);
        }

        [Fact]
        public void Index_SortByDate_ReturnsSortedByDate()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            var dates = model.Select(s => s.EnrollmentDate).ToList();
            var sortedDates = dates.OrderBy(d => d).ToList();
            Assert.Equal(sortedDates, dates);
        }

        [Fact]
        public void Index_SortByDateDesc_ReturnsSortedByDateDesc()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            var dates = model.Select(s => s.EnrollmentDate).ToList();
            var sortedDates = dates.OrderByDescending(d => d).ToList();
            Assert.Equal(sortedDates, dates);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Carson", model.First().FirstMidName);
        }

        [Fact]
        public void Index_SearchStringNull_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, 1) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAsc()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
